CREATE TABLE IF NOT EXISTS services (id SERIAL PRIMARY KEY, name VARCHAR(255) NOT NULL, slug VARCHAR(255) NOT NULL UNIQUE, short_description TEXT, description TEXT, image_url TEXT, icon VARCHAR(100), price_from NUMERIC(12,2), is_active BOOLEAN DEFAULT true, sort_order INT DEFAULT 0, created_at TIMESTAMPTZ DEFAULT NOW()); CREATE TABLE IF NOT EXISTS portfolio (id SERIAL PRIMARY KEY, title VARCHAR(255) NOT NULL, client_task TEXT, specs TEXT, image_url TEXT, gallery JSONB DEFAULT '[]', category VARCHAR(100), is_active BOOLEAN DEFAULT true, sort_order INT DEFAULT 0, created_at TIMESTAMPTZ DEFAULT NOW());